PROCEDURE TCP_Server_Service
BEGIN
 // Server prepares for connections (passive open)
 SOCKET ← CREATE_SOCKET()
 PORT ← 8080 // Well-known port
 BIND(SOCKET, PORT)

 // LISTEN primitive - wait for connection requests
 LISTEN(SOCKET, queue_size=5)

 // ACCEPT - get incoming connection
 NEW_SOCKET ← ACCEPT(SOCKET)

 // RECEIVE - get data from client
 DATA ← RECEIVE(NEW_SOCKET)

 // Process data
 RESPONSE ← PROCESS(DATA)

 // SEND - transmit response
 SEND(NEW_SOCKET, RESPONSE)

 // CLOSE - terminate connection
 CLOSE(NEW_SOCKET)
END

PROCEDURE UDP_Client_Service
BEGIN
 // Create socket without connection setup
 SOCKET ← CREATE_SOCKET()

 SERVER_IP ← "192.168.1.100"
 SERVER_PORT ← 53 // DNS port

 MESSAGE ← "Resolve domain"

 // SENDTO - send datagram (connectionless)
 SENDTO(SOCKET, MESSAGE, SERVER_IP, SERVER_PORT)

 // Set timeout for response
 TIMEOUT ← 5 seconds

 // RECEIVEFROM - receive response
 DATA, SOURCE_IP, SOURCE_PORT ← 
 RECEIVEFROM(SOCKET, TIMEOUT)

 // Process response
 PROCESS(DATA)

 // Close socket
 CLOSE(SOCKET)
END
